const { app, BrowserWindow, globalShortcut } = require('electron');
const path = require('path');

let mainWindow;

function createWindow() {
  mainWindow = new BrowserWindow({
    width: 1200,
    height: 900,
    // Kiosk-Modus sorgt dafür, dass die App den ganzen Bildschirm einnimmt
    // und nicht einfach mit Alt-Tab oder der Windows-Taste verlassen werden kann.
    kiosk: true, 
    webPreferences: {
      nodeIntegration: false, // Sicherheit: Kein direkter Node-Zugriff aus dem Frontend
      contextIsolation: true,
      preload: path.join(__dirname, 'preload.js') // Optional für tiefere Systemintegration
    },
    icon: path.join(__dirname, 'icon.png') // Pfad zu deinem App-Icon
  });

  // Lädt deine lokale HTML Datei
  mainWindow.loadFile('src/index.html');

  // Deaktiviert das Standard-Menü (Datei, Bearbeiten, etc.)
  mainWindow.setMenu(null);

  // Verhindert das Schließen per Alt+F4 während der Präsentation (optional)
  mainWindow.on('close', (e) => {
    // e.preventDefault(); 
  });
}

app.whenReady().then(() => {
  createWindow();

  // Sicherheits-Feature: Beenden der Präsentation nur über einen geheimen Shortcut
  globalShortcut.register('CommandOrControl+Shift+Q', () => {
    app.quit();
  });
});

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') app.quit();
});

/**
 * BUNDESWAHLAPP - SINGLE FILE LOGIC
 * Architektur: Vanilla JS State-Management mit funktionalem Rendering.
 * Simuliert: React-ähnlichen Unidirektionalen Datenfluss.
 * * WICHTIG: Die ELECTIONS-Daten werden in den Zustand kopiert,
 * damit der Status ('voted') aktualisiert werden kann.
 */

// --- MOCK DATEN (Basis) ---
const ELECTIONS_BASE = [
    {
        id: 'bt-2025',
        title: 'Bundestagswahl 2025',
        type: 'parliament',
        status: 'open',
        info: 'Wahl zum 21. Deutschen Bundestag',
        candidates: [
            { id: 'c1', name: 'Dr. Anna Schmidt', party: 'Demokratische Union', desc: 'Direktkandidatin Wahlkreis 042' },
            { id: 'c2', name: 'Markus Weber', party: 'Soziale Zukunft', desc: 'Direktkandidat Wahlkreis 042' }
        ],
        parties: [
            { id: 'p1', name: 'Demokratische Union (DU)', desc: 'Konservativ-Liberal' },
            { id: 'p2', name: 'Soziale Zukunft (SZ)', desc: 'Sozialdemokratisch' },
            { id: 'p3', name: 'Grüne Innovation (GI)', desc: 'Ökologisch-Progressiv' }
        ]
    },
    {
        id: 've-mobil',
        title: 'Volksentscheid: Mobilität',
        type: 'referendum',
        status: 'open',
        question: 'Soll der Ausbau des öffentlichen Nahverkehrs (ÖPNV) vorrangig vor dem Straßenbau gefördert werden?',
        options: [
            { id: 'ja', name: 'JA', desc: 'Zustimmung zum Gesetzesentwurf' },
            { id: 'nein', name: 'NEIN', desc: 'Ablehnung des Gesetzesentwurf' }
        ]
    }
];

// --- KONFIGURATION & DATEN ---
const CONSTANTS = {
    CORRECT_PIN: '123456',
    API_DELAY: 1500,
    NFC_SCAN_TIME: 3000
};

// --- STATE MANAGEMENT ---
const state = {
    view: 'login',          
    user: null,             
    // WICHTIG: Erstellen einer tiefen Kopie, um den Status ändern zu können
    elections: JSON.parse(JSON.stringify(ELECTIONS_BASE)), 
    selectedElection: null, 
    votes: {                
        first: null,
        second: null
    },
    pinInput: '',
    error: null,
    isLoading: false,
    loadingMessage: '',
    nfcActive: false,       
    menuOpen: false
};

// --- CORE RENDER ENGINE ---
function render() {
    const root = document.getElementById('app-root');
    root.innerHTML = ''; 

    // 1. Header (immer sichtbar außer bei Vollbild-Overlays wie NFC)
    if (!state.nfcActive) {
        root.appendChild(Components.Header());
    }

    // 2. Main Content Routing
    const main = document.createElement('main');
    main.className = "flex-grow overflow-y-auto pb-24 relative w-full"; 

    switch(state.view) {
        case 'login': main.appendChild(Views.Login()); break;
        case 'nfc_simulation': main.appendChild(Views.NfcSimulation()); break;
        case 'pin_entry': main.appendChild(Views.PinEntry()); break;
        case 'dashboard': main.appendChild(Views.Dashboard()); break;
        case 'voting': main.appendChild(Views.Voting()); break;
        case 'confirmation': main.appendChild(Views.Confirmation()); break;
        case 'success': main.appendChild(Views.Success()); break;
        case 'about': main.appendChild(Views.About()); break;
    }
    root.appendChild(main);

    // 3. Overlays & Modals
    if (state.menuOpen) root.appendChild(Components.MenuModal());
    if (state.isLoading) root.appendChild(Components.LoadingOverlay());

    // 4. PersoSim Overlay (Besonderes Feature)
    if (state.nfcActive) root.appendChild(Components.PersoSimOverlay());
}

// Update State Helper
function setState(newState) {
    Object.assign(state, newState);
    render(); 
}


// --- COMPONENTS (UI BAUSTEINE) ---
const Components = {
    Header: () => {
        const el = document.createElement('header');
        el.className = "bg-white border-b border-slate-200 h-16 flex items-center justify-between px-4 shrink-0 z-20";
        el.innerHTML = `
            <div class="flex items-center gap-2">
                <!-- APP LOGO ICON -->
                <div class="bg-blue-700 text-white p-1.5 rounded-lg">
                    <i class="ph-bold ph-archive-box text-xl"></i>
                </div>
                <div class="leading-none">
                    <h1 class="font-bold text-slate-800 text-lg">BundesWahl<span class="text-blue-600">App</span></h1>
                    <span class="text-[10px] text-slate-400 tracking-widest uppercase font-medium">Offiziell</span>
                </div>
            </div>
            <button onclick="Actions.toggleMenu()" class="p-2 text-slate-600 hover:bg-slate-100 rounded-full transition">
                <i class="ph-bold ph-list text-2xl"></i>
            </button>
        `;
        return el;
    },

    LoadingOverlay: () => {
        const el = document.createElement('div');
        el.className = "absolute inset-0 bg-white/90 backdrop-blur-sm z-50 flex flex-col items-center justify-center fade-in";
        el.innerHTML = `
            <div class="w-12 h-12 border-4 border-blue-200 border-t-blue-600 rounded-full animate-spin mb-4"></div>
            <p class="text-slate-600 font-medium animate-pulse">${state.loadingMessage || 'Verarbeite...'}</p>
        `;
        return el;
    },

    PersoSimOverlay: () => {
        const el = document.createElement('div');
        el.className = "absolute inset-0 bg-slate-900 z-50 flex flex-col items-center justify-center text-white p-6 fade-in";
        // Simuliert die native Schnittstelle von Android für NFC
        el.innerHTML = `
            <div class="absolute top-0 left-0 w-full p-4 flex justify-between items-center opacity-50">
                <span class="text-xs font-mono">PersoSim Simulator Interface</span>
                <i class="ph-fill ph-wifi-high"></i>
            </div>

            <div class="relative flex items-center justify-center mb-10">
                <div class="nfc-ripple"></div>
                <div class="nfc-ripple"></div>
                <div class="nfc-ripple"></div>
                <i class="ph-duotone ph-identification-card text-8xl relative z-10 text-blue-400"></i>
            </div>

            <h2 class="text-2xl font-bold mb-2 text-center">Ausweis bereit</h2>
            <p class="text-slate-300 text-center mb-8 max-w-xs">
                Halten Sie Ihren Personalausweis an die Rückseite Ihres Gerätes, um die eID-Funktion zu nutzen.
            </p>

            <div class="bg-slate-800 rounded-lg p-4 w-full max-w-xs border border-slate-700 flex items-center gap-3">
                <div class="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                <span class="text-sm text-slate-300 font-mono">Scanner aktiv...</span>
            </div>

            <button onclick="Actions.cancelNfc()" class="mt-12 text-slate-400 hover:text-white text-sm font-medium py-2 px-6 border border-slate-600 rounded-full">
                Abbrechen
            </button>
        `;

        // Auto-Trigger success after 3 seconds
        setTimeout(() => Actions.nfcScanSuccess(), 3000);

        return el;
    },

    MenuModal: () => {
        const el = document.createElement('div');
        el.className = "absolute inset-0 bg-black/50 z-40";
        el.onclick = (e) => { if(e.target === el) Actions.toggleMenu(); };

        const content = document.createElement('div');
        content.className = "absolute top-0 right-0 w-3/4 max-w-sm h-full bg-white shadow-2xl p-6 slide-in-right flex flex-col";
        content.innerHTML = `
            <div class="flex justify-end mb-8">
                <button onclick="Actions.toggleMenu()" class="p-2 bg-slate-100 rounded-full text-slate-500">
                    <i class="ph-bold ph-x text-xl"></i>
                </button>
            </div>
            <nav class="space-y-2">
                ${state.user ? `
                    <div class="p-4 bg-blue-50 rounded-xl mb-6 border border-blue-100">
                        <div class="text-xs text-blue-600 font-bold uppercase tracking-wider mb-1">Angemeldet als</div>
                        <div class="font-bold text-slate-800">${state.user.name}</div>
                        <div class="text-xs text-slate-500 mt-1 font-mono">ID: ${state.user.id}</div>
                    </div>
                ` : ''}

                <button onclick="Actions.navigateTo('about')" class="w-full text-left p-4 rounded-xl hover:bg-slate-50 flex items-center gap-3 text-slate-700 font-medium">
                    <i class="ph-bold ph-info text-blue-600"></i> Über die App & FAQ
                </button>
                <button onclick="window.open('https://github.com/PersoSim', '_blank')" class="w-full text-left p-4 rounded-xl hover:bg-slate-50 flex items-center gap-3 text-slate-700 font-medium">
                    <i class="ph-bold ph-code text-blue-600"></i> PersoSim Projekt
                </button>
            </nav>

            ${state.user ? `
                <div class="mt-auto border-t border-slate-100 pt-6">
                    <button onclick="Actions.logout()" class="w-full py-3 rounded-xl bg-red-50 text-red-600 font-bold flex items-center justify-center gap-2 hover:bg-red-100 transition">
                        <i class="ph-bold ph-sign-out"></i> Abmelden
                    </button>
                </div>
            ` : ''}
        `;
        el.appendChild(content);
        return el;
    },

    PinPad: () => {
        const pad = document.createElement('div');
        pad.className = "mt-auto w-full max-w-[300px] mx-auto";

        // Display
        const display = document.createElement('div');
        display.className = "flex justify-center gap-3 mb-8";
        for (let i=0; i<6; i++) {
            const dot = document.createElement('div');
            const active = i < state.pinInput.length;
            dot.className = `w-4 h-4 rounded-full border-2 transition-all duration-200 ${active ? 'bg-blue-600 border-blue-600 scale-110' : 'bg-transparent border-slate-300'}`;
            display.appendChild(dot);
        }
        pad.appendChild(display);

        // Grid
        const grid = document.createElement('div');
        grid.className = "grid grid-cols-3 gap-4";

        const keys = ['1','2','3','4','5','6','7','8','9','del','0','ok'];

        keys.forEach(k => {
            const btn = document.createElement('button');
            // Spezielles Styling für Funktionstasten
            if (k === 'ok') {
                btn.className = "aspect-square rounded-2xl flex items-center justify-center text-2xl font-bold shadow-sm bg-blue-600 text-white active:bg-blue-700 transition";
                btn.innerHTML = `<i class="ph-bold ph-check"></i>`;
                btn.onclick = () => Actions.submitPin();
                if (state.pinInput.length !== 6) btn.classList.add('opacity-50', 'cursor-not-allowed');
            } else if (k === 'del') {
                btn.className = "aspect-square rounded-2xl flex items-center justify-center text-2xl font-bold shadow-sm bg-slate-200 text-slate-600 active:bg-slate-300 transition";
                btn.innerHTML = `<i class="ph-bold ph-backspace"></i>`;
                btn.onclick = () => Actions.pinInput('del');
            } else {
                btn.className = "pin-btn aspect-square rounded-2xl flex items-center justify-center text-2xl font-bold text-slate-700 shadow-sm border border-slate-200";
                btn.textContent = k;
                btn.onclick = () => Actions.pinInput(k);
            }
            grid.appendChild(btn);
        });

        pad.appendChild(grid);
        return pad;
    }
};

// --- VIEWS (SEITEN) ---
const Views = {
    Login: () => {
        const el = document.createElement('div');
        el.className = "p-6 flex flex-col h-full justify-center fade-in";
        el.innerHTML = `
            <div class="text-center mb-10">
                <div class="w-20 h-20 bg-blue-50 rounded-3xl flex items-center justify-center mx-auto mb-6 text-blue-600 shadow-inner">
                    <i class="ph-duotone ph-fingerprint text-5xl"></i>
                </div>
                <h2 class="text-2xl font-bold text-slate-800 mb-2">Willkommen</h2>
                <p class="text-slate-500 leading-relaxed">
                    Bitte identifizieren Sie sich mit Ihrem Personalausweis, um sicher an Wahlen teilzunehmen.
                </p>
            </div>

            <button onclick="Actions.startNfc()" class="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold shadow-lg shadow-blue-200 active:scale-[0.98] transition flex items-center justify-center gap-3 text-lg">
                <i class="ph-bold ph-identification-card text-2xl"></i>
                Mit BundID anmelden
            </button>

            <div class="mt-6 flex items-center justify-center gap-2 text-xs text-slate-400">
                <i class="ph-fill ph-shield-check text-green-500"></i>
                <span>Ende-zu-Ende verschlüsselt via PersoSim</span>
            </div>
        `;
        return el;
    },

    PinEntry: () => {
        const el = document.createElement('div');
        el.className = "p-6 flex flex-col h-full pt-10 fade-in";

        const header = document.createElement('div');
        header.className = "text-center mb-4";
        header.innerHTML = `
            <h2 class="text-xl font-bold text-slate-800">2-Faktor Schutz</h2>
            <p class="text-sm text-slate-500 mt-1">Bitte geben Sie Ihre 6-stellige eID-PIN ein.</p>
        `;
        el.appendChild(header);

        if (state.error) {
            const err = document.createElement('div');
            err.className = "bg-red-50 text-red-600 p-3 rounded-lg text-sm text-center mb-4 border border-red-100";
            err.innerHTML = `<i class="ph-bold ph-warning mr-1"></i> ${state.error}`;
            el.appendChild(err);
        }

        el.appendChild(Components.PinPad());

        return el;
    },

    Dashboard: () => {
        const el = document.createElement('div');
        el.className = "p-4 space-y-4 fade-in";

        const welcome = document.createElement('div');
        welcome.className = "mb-6 mt-2";
        welcome.innerHTML = `
            <h2 class="text-2xl font-bold text-slate-800">Hallo, ${state.user.name.split(' ')[0]}</h2>
            <div class="flex items-center gap-2 text-sm text-green-600 mt-1 bg-green-50 inline-block px-3 py-1 rounded-full border border-green-100">
                <i class="ph-bold ph-check-circle"></i> Identität verifiziert
            </div>
        `;
        el.appendChild(welcome);

        // Wahlkarten
        state.elections.forEach(e => {
            const isVoted = e.status === 'voted';
            const isOpen = e.status === 'open';

            const statusClass = isVoted ? 'bg-blue-100 text-blue-700' : 
                                  (isOpen ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-500');
            const statusText = isVoted ? 'Abgestimmt' : 
                                (isOpen ? 'Offen' : 'Geschlossen');
            const cardClass = isVoted ? 'bg-blue-50 border-blue-200' : 
                                (isOpen ? 'bg-white border-slate-100 cursor-pointer transition active:scale-[0.98]' : 'opacity-70 grayscale bg-white border-slate-100');

            const card = document.createElement('div');
            card.className = `p-5 rounded-2xl shadow-sm border relative overflow-hidden ${cardClass}`;
            if (isOpen) card.onclick = () => Actions.selectElection(e);

            card.innerHTML = `
                <div class="absolute top-0 right-0 w-24 h-24 bg-gradient-to-br ${isOpen ? 'from-blue-500/10 to-transparent' : (isVoted ? 'from-blue-200/50 to-transparent' : 'from-slate-200 to-transparent')} rounded-bl-full -mr-4 -mt-4 pointer-events-none"></div>
                <div class="flex justify-between items-start mb-2 relative z-10">
                    <div class="bg-slate-100 p-2 rounded-lg text-slate-600">
                        <i class="ph-bold ${e.type === 'parliament' ? 'ph-bank' : 'ph-users-three'} text-xl"></i>
                    </div>
                    <span class="${statusClass} text-[10px] font-bold px-2 py-1 rounded-full uppercase">${statusText}</span>
                </div>
                <h3 class="font-bold text-lg text-slate-800 relative z-10">${e.title}</h3>
                <p class="text-sm text-slate-500 mt-1 line-clamp-2 relative z-10">${e.type === 'parliament' ? 'Wählen Sie Ihre Vertreter.' : 'Stimmen Sie über Sachfragen ab.'}</p>

                ${isVoted ? `
                    <div class="mt-3 text-sm font-medium text-blue-600 flex items-center gap-1">
                        <i class="ph-bold ph-check"></i> Ihre Stimme wurde registriert.
                    </div>
                ` : ''}
            `;
            el.appendChild(card);
        });

        return el;
    },

    Voting: () => {
        const e = state.selectedElection;
        const isReferendum = e.type === 'referendum';

        const el = document.createElement('div');
        el.className = "flex flex-col h-full fade-in";
        el.innerHTML = `
            <div class="p-4 border-b border-slate-100 bg-white sticky top-0 z-10 flex items-center gap-3">
                <button onclick="Actions.navigateTo('dashboard')" class="p-2 hover:bg-slate-50 rounded-full"><i class="ph-bold ph-arrow-left text-xl"></i></button>
                <div class="font-bold text-slate-800 truncate">${e.title}</div>
            </div>
            <div class="p-4 space-y-6 pb-32">
                ${isReferendum ? `
                    <div class="bg-blue-50 p-4 rounded-xl border border-blue-100">
                        <h4 class="font-bold text-blue-900 mb-2"><i class="ph-bold ph-question mr-1"></i> Frage</h4>
                        <p class="text-blue-800 text-sm leading-relaxed">${e.question}</p>
                    </div>
                    <div class="space-y-3">
                        ${e.options.map(opt => `
                            <div onclick="Actions.vote('first', '${opt.id}')" 
                                 class="p-4 rounded-xl border-2 transition flex items-center justify-between cursor-pointer ${state.votes.first === opt.id ? 'border-blue-600 bg-blue-50' : 'border-slate-200 bg-white'}">
                                <span class="font-bold ${state.votes.first === opt.id ? 'text-blue-700' : 'text-slate-700'}">${opt.name}</span>
                                ${state.votes.first === opt.id ? '<i class="ph-fill ph-check-circle text-2xl text-blue-600"></i>' : '<div class="w-6 h-6 rounded-full border-2 border-slate-300"></div>'}
                            </div>
                        `).join('')}
                    </div>
                ` : `
                    <!-- Parlamentswahl -->
                    <div>
                        <h4 class="font-bold text-slate-700 mb-3 uppercase text-xs tracking-wider">Erststimme (Kandidat)</h4>
                        <div class="space-y-3">
                            ${e.candidates.map(c => `
                                <div onclick="Actions.vote('first', '${c.id}')" 
                                     class="p-3 rounded-xl border-2 transition cursor-pointer ${state.votes.first === c.id ? 'border-blue-600 bg-blue-50' : 'border-slate-200 bg-white'}">
                                    <div class="flex justify-between">
                                        <div class="font-bold text-slate-800">${c.name}</div>
                                        ${state.votes.first === c.id ? '<i class="ph-fill ph-check-circle text-blue-600"></i>' : ''}
                                    </div>
                                    <div class="text-xs text-slate-500 mt-1">${c.party}</div>
                                </div>
                            `).join('')}
                        </div>
                    </div>
                    <div>
                        <h4 class="font-bold text-slate-700 mb-3 mt-2 uppercase text-xs tracking-wider">Zweitstimme (Partei)</h4>
                        <div class="space-y-3">
                            ${e.parties.map(p => `
                                <div onclick="Actions.vote('second', '${p.id}')" 
                                     class="p-3 rounded-xl border-2 transition cursor-pointer ${state.votes.second === p.id ? 'border-indigo-600 bg-indigo-50' : 'border-slate-200 bg-white'}">
                                    <div class="flex justify-between">
                                        <div class="font-bold text-slate-800">${p.name}</div>
                                        ${state.votes.second === p.id ? '<i class="ph-fill ph-check-circle text-indigo-600"></i>' : ''}
                                    </div>
                                    <div class="text-xs text-slate-500 mt-1">${p.desc}</div>
                                </div>
                            `).join('')}
                        </div>
                    </div>
                `}
            </div>

            <!-- Sticky Footer Button -->
            <div class="fixed bottom-0 left-0 w-full p-4 bg-white border-t border-slate-200 z-10 safe-area-bottom">
                <button onclick="Actions.goToReview()" 
                        ${!Actions.isVoteComplete() ? 'disabled' : ''}
