// --- ACTIONS (Controller Logic) ---
const Actions = {
    navigateTo: (view) => {
        state.view = view;
        render();
    },

    toggleMenu: () => {
        state.menuOpen = !state.menuOpen;
        render();
    },

    startNfc: () => {
        // Simuliere den Start der PersoSim App / NFC Suche
        state.nfcActive = true;
        render();
    },

    cancelNfc: () => {
        state.nfcActive = false;
        render();
    },

    nfcScanSuccess: () => {
        state.nfcActive = false;
        state.loadingMessage = "Lese Zertifikate...";
        state.isLoading = true;
        render();

        // Nach kurzer Ladezeit zur PIN-Eingabe
        setTimeout(() => {
            state.isLoading = false;
            state.view = 'pin_entry';
            render();
        }, 1500);
    },

    pinInput: (val) => {
        if (val === 'del') state.pinInput = state.pinInput.slice(0, -1);
        else if (state.pinInput.length < 6) state.pinInput += val;
        state.error = null;
        render();
    },

    submitPin: () => {
        state.isLoading = true;
        state.loadingMessage = "Prüfe PIN...";
        render();

        setTimeout(() => {
            state.isLoading = false;
            if (state.pinInput === CONSTANTS.CORRECT_PIN) {
                state.user = { name: 'Max Mustermann', id: 'L029384', verified: true };
                state.view = 'dashboard';
                state.pinInput = '';
            } else {
                state.error = "Falsche PIN. (Hinweis: 123456)";
                state.pinInput = '';
                state.view = 'pin_entry'; 
            }
            render();
        }, 1000);
    },

    selectElection: (election) => {
        state.selectedElection = election;
        state.votes = { first: null, second: null }; // Reset
        state.view = 'voting';
        render();
    },

    vote: (type, id) => {
        state.votes[type] = id;
        render();
    },

    isVoteComplete: () => {
        if (!state.selectedElection) return false;
        if (state.selectedElection.type === 'parliament') {
            return state.votes.first && state.votes.second;
        }
        return state.votes.first; 
    },

    goToReview: () => {
        state.view = 'confirmation';
        render();
    },

    getLabel: (id) => {
        // Helper to find name by ID
        const e = state.selectedElection;
        let found = e.candidates?.find(c => c.id === id) || 
                    e.parties?.find(p => p.id === id) || 
                    e.options?.find(o => o.id === id);
        return found ? found.name : id;
    },

    submitVote: () => {
        state.isLoading = true;
        state.loadingMessage = "Signiere & Übertrage...";
        render();

        setTimeout(() => {
            // WICHTIG: Status der Wahl im State auf 'voted' setzen
            const currentElectionId = state.selectedElection.id;
            const updatedElections = state.elections.map(e => {
                if (e.id === currentElectionId) {
                    // Setze den Status auf "voted" (abgestimmt)
                    return { ...e, status: 'voted' };
                }
                return e;
            });

            setState({
                isLoading: false,
                view: 'success',
                elections: updatedElections // Aktualisiere die globale Wahlliste
            });

        }, 2000);
    },

    logout: () => {
        state.user = null;
        state.menuOpen = false;
        state.view = 'login';
        render();
    }
};

